SELECT COUNT(*) AS total_payments
FROM payment_history
WHERE payment_amount = (
    SELECT MAX(payment_amount)
    FROM payment_history
);

SELECT AVG(rental_yield) AS average_rental_yield
FROM market_indicators
WHERE avg_sale_price > 200000;

SELECT metro_population, metro_area_sqmi
FROM metros
WHERE metro_population = (SELECT MIN(metro_population) FROM metros);

SELECT regions.region_name, regions.region_type, market_indicators.pct_price_cut
FROM regions
INNER JOIN market_indicators ON regions.region_id = market_indicators.region_id;

SELECT region_id, AVG(rental_yield) AS average_rental_yield
FROM market_indicators
GROUP BY region_id;

SELECT DISTINCT r.region_type
FROM regions r
WHERE r.region_id NOT IN (
    SELECT DISTINCT user_id 
    FROM user_activity
);
